const e=JSON.parse(`{"key":"v-38d065a9","path":"/vanblog/Docker%E4%BD%BF%E7%94%A8%E6%95%99%E7%A8%8B.html","title":"简介","lang":"zh-CN","frontmatter":{"description":"简介 Docker是一个开源的应用容器引擎，基于 Go 语言 并遵从 Apache2.0 协议开源。Docker 可以让开发者打包他们的应用以及依赖包到一个轻量级、可移植的容器中，然后发布到任何流行的 Linux 机器上，也可以实现虚拟化。容器是完全使用沙箱机制，相互之间不会有任何接口（类似 iPhone 的 app）,更重要的是容器性能开销极低。 Docker的核心是Docker引擎，它是一个轻量级的容器化技术，可以在Linux、Windows和Mac上运行。Docker引擎可以将应用程序及其依赖项打包到一个可移植的容器中，从而实现快速部署、可移植性和可伸缩性。Docker引擎还提供了一组API，可以用于管理和监视容器。 Docker镜像生命周期： 官网：https://www.docker.com/ engine文档：https://docs.docker.com/engine/ Dockerfile文档： https://docs.docker.com/engine/reference/builder/ compose-file文档：https://docs.docker.com/compose/compose-file/05-services/","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/vanblog/Docker%E4%BD%BF%E7%94%A8%E6%95%99%E7%A8%8B.html"}],["meta",{"property":"og:site_name","content":"Kevin2li's Blog"}],["meta",{"property":"og:title","content":"简介"}],["meta",{"property":"og:description","content":"简介 Docker是一个开源的应用容器引擎，基于 Go 语言 并遵从 Apache2.0 协议开源。Docker 可以让开发者打包他们的应用以及依赖包到一个轻量级、可移植的容器中，然后发布到任何流行的 Linux 机器上，也可以实现虚拟化。容器是完全使用沙箱机制，相互之间不会有任何接口（类似 iPhone 的 app）,更重要的是容器性能开销极低。 Docker的核心是Docker引擎，它是一个轻量级的容器化技术，可以在Linux、Windows和Mac上运行。Docker引擎可以将应用程序及其依赖项打包到一个可移植的容器中，从而实现快速部署、可移植性和可伸缩性。Docker引擎还提供了一组API，可以用于管理和监视容器。 Docker镜像生命周期： 官网：https://www.docker.com/ engine文档：https://docs.docker.com/engine/ Dockerfile文档： https://docs.docker.com/engine/reference/builder/ compose-file文档：https://docs.docker.com/compose/compose-file/05-services/"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-05-22T06:31:47.000Z"}],["meta",{"property":"article:author","content":"Kevin2li"}],["meta",{"property":"article:modified_time","content":"2023-05-22T06:31:47.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"简介\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-05-22T06:31:47.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Kevin2li\\",\\"url\\":\\"https://blog.kevin2li.top\\"}]}"]]},"headers":[{"level":2,"title":"镜像管理","slug":"镜像管理","link":"#镜像管理","children":[]},{"level":2,"title":"容器管理","slug":"容器管理","link":"#容器管理","children":[]},{"level":2,"title":"网络管理","slug":"网络管理","link":"#网络管理","children":[]},{"level":2,"title":"数据卷管理","slug":"数据卷管理","link":"#数据卷管理","children":[]},{"level":2,"title":"镜像加速","slug":"镜像加速","link":"#镜像加速","children":[]}],"git":{"createdTime":1684730003000,"updatedTime":1684737107000,"contributors":[{"name":"kevin2li","email":"kevin2li@qq.com","commits":3}]},"readingTime":{"minutes":2.46,"words":738},"filePathRelative":"vanblog/Docker使用教程.md","localizedDate":"2023年5月22日","excerpt":"<h1> 简介</h1>\\n<p>Docker是一个开源的应用容器引擎，基于 Go 语言 并遵从 Apache2.0 协议开源。Docker 可以让开发者打包他们的应用以及依赖包到一个轻量级、可移植的容器中，然后发布到任何流行的 Linux 机器上，也可以实现虚拟化。容器是完全使用沙箱机制，相互之间不会有任何接口（类似 iPhone 的 app）,更重要的是容器性能开销极低。</p>\\n<p>Docker的核心是Docker引擎，它是一个轻量级的容器化技术，可以在Linux、Windows和Mac上运行。Docker引擎可以将应用程序及其依赖项打包到一个可移植的容器中，从而实现快速部署、可移植性和可伸缩性。Docker引擎还提供了一组API，可以用于管理和监视容器。</p>\\n<p><strong>Docker镜像生命周期：</strong>\\n<img src=\\"https://minio.kevin2li.top/image-bed/vanblog/img/55f78e2df8a5e9d5f1044eab3792e4ef.640.jpg\\" alt=\\"640.jpg\\" loading=\\"lazy\\"></p>\\n<p>官网：<a href=\\"https://www.docker.com/\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">https://www.docker.com/</a><br>\\nengine文档：<a href=\\"https://docs.docker.com/engine/\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">https://docs.docker.com/engine/</a><br>\\nDockerfile文档： <a href=\\"https://docs.docker.com/engine/reference/builder/\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">https://docs.docker.com/engine/reference/builder/</a><br>\\ncompose-file文档：<a href=\\"https://docs.docker.com/compose/compose-file/05-services/\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">https://docs.docker.com/compose/compose-file/05-services/</a></p>\\n","autoDesc":true}`);export{e as data};
